jsLib:
function getBase(){return 'https://fq-tt-worker.ch6vip.workers.dev';}
function enc(v){return encodeURIComponent(String(v==null?'':v));}
function html(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function clean(s){return String(s==null?'':s).replace(/<\/?em>/g,'').replace(/<[^>]+>/g,'');}
function getBaseUrl(){return typeof baseUrl==='undefined'?'':String(baseUrl||'');}
function param(name){var m=getBaseUrl().match(new RegExp('[?&]'+name+'=([^&]*)'));return m?decodeURIComponent(m[1]):'';}
function buildBookUrl(b){return getBase()+'/?api=book&book_id='+enc(b.book_id)+'&name='+enc(b.book_name||b.raw_book_name||'')+'&author='+enc(b.author||'')+'&cover='+enc(b.thumb_url||b.detail_page_thumb_url||'')+'&intro='+enc(b.abstract||b.book_abstract_v2||'')+'&kind='+enc(b.category||b.pure_category_tags||'')+'&word='+enc(b.word_number||'')+'&last='+enc(b.last_chapter_title||'');}
function normalizeSearch(payload){var root=(payload&&payload.data)||payload||{};var tabs=root.search_tabs||[];var out=[];var seen={};for(var i=0;i<tabs.length;i++){var list=tabs[i].data||[];for(var j=0;j<list.length;j++){var cell=list[j]||{};var books=cell.book_data||[];for(var k=0;k<books.length;k++){var b=books[k]||{};if(!b.book_id||seen[b.book_id])continue;seen[b.book_id]=1;b.bookUrl=buildBookUrl(b);out.push(b);}}}return out;}
function commentPageUrl(bookId,itemId,para){return getBase()+'/?api=comment_page&book_id='+enc(bookId)+'&item_id='+enc(itemId)+'&para_index='+enc(para)+'&offset=0&count=100';}
function commentTag(bookId,itemId,para){var url=commentPageUrl(bookId,itemId,para);var click='java.showBrowser(\\\"'+url+'\\\")';var src=getBase()+'/comment-icon.svg?'+para+",{'click':'"+click+"','style':'TEXT'}";return '<img src="'+src+'">';}
function addCommentEntries(content,bookId,itemId){if(!content||!bookId||!itemId)return content;var lines=String(content).split('\n');for(var i=0;i<lines.length;i++){if(String(lines[i]).trim()){lines[i]=lines[i]+commentTag(bookId,itemId,i);}}return lines.join('\n');}
